import React, { useEffect, useState } from 'react';
//import './styles/App.css';
import axios from 'axios';
import { BrowserRouter as Router, Route, Routes, Navigate } from 'react-router-dom';
import Login from './pages/Login';
import Home from './pages/HomePage/Home';
import Admin from './pages/Admin/Admin';
import Register from './pages/Register';
//import 'bootstrap/dist/css/bootstrap.min.css';
function App() {
  const [token, setToken] = useState(localStorage.getItem('token'));

  const handleLogin = (newToken) => {
    setToken(newToken);
    localStorage.setItem('token', newToken);
    localStorage.setItem('is_admin', isAdmin);
  };
  const handleLogout = () => {
    setToken(null);
    localStorage.removeItem('token');
  };
const ProtectedRoute = ({ token, requiredAdmin, children }) => {
    const isAdmin = localStorage.getItem("is_admin") === "true";
    if (!token) {
        return <Navigate to="/login" />;
    }
    if (requiredAmin && !isAdmin) {
        return <Navigate to="/home" />;
    }
    else {
        return children;
    }
};
/*const ProtectedRouteHome = ({ token, children }) => {
    if (!token) {
        return <Navigate to="/login" />;
    }
    else {
        return children;
    }
};
*/

  return (
    <Router>
      <Routes>
        <Route path="/register" element={<Register />} />
        <Route path="/login" element={<Login setToken={handleLogin} />} />
        <Route path="/" element={token ? <Register token={token} /> : <Navigate to="/login" />} />
        <Route path="/admin" element={ <ProtectedRoute token={token} requiredAdmin={true}> <Admin handleLogout={handleLogout}/></ProtectedRoute>}/>
        <Route path="/home" element={<ProtectedRoute token={token}> <Home setToken={setToken} handleLogout={handleLogout}/></ProtectedRoute>} />
      </Routes>
    </Router>
  );
}

export default App;
